const i = $input.first().json;

const UUID_RE = /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i;

function nullableInt(value) {
  if (value === null || value === undefined || value === '') {
    return null;
  }
  const n = typeof value === 'number' ? value : Number(value);
  if (!Number.isFinite(n)) {
    return null;
  }
  return Math.trunc(n);
}

function nullableUsd(value) {
  if (value === null || value === undefined || value === '') {
    return null;
  }
  const n = typeof value === 'number' ? value : Number(value);
  if (!Number.isFinite(n)) {
    return null;
  }
  return Number(n.toFixed(6));
}

const rawUid = i.userId != null ? String(i.userId).trim() : '';
const userUuid = rawUid && UUID_RE.test(rawUid) ? rawUid.toLowerCase() : null;

const wf = i.workflowId != null ? String(i.workflowId).trim() : '';

return [{
  json: {
    payload: {
      provider: String(i.provider || 'unknown').slice(0, 128),
      model: String(i.model || 'unknown').slice(0, 256),
      latency_ms: nullableInt(i.latencyMs),
      prompt_tokens: nullableInt(i.promptTokens),
      completion_tokens: nullableInt(i.completionTokens),
      cost_usd: nullableUsd(i.costUsd),
      user_id: userUuid,
      workflow_id: wf === '' ? null : wf.slice(0, 256),
    },
  },
}];

const http = $input.first().json;
const built = $('Build Payload').first().json;
const status = Number(http.statusCode ?? http.status ?? 0);
let row = {};
try {
  const raw = http.body ?? http.data ?? '';
  const parsed = typeof raw === 'string' ? JSON.parse(raw) : raw;
  row = Array.isArray(parsed) ? (parsed[0] || {}) : parsed;
} catch (_) {
  row = {};
}
if (status >= 400) {
  throw new Error('Supabase insert failed (' + status + '): ' + JSON.stringify(http.body ?? http.data));
}
return [{
  json: {
    ok: true,
    status,
    payload: built.payload,
    row,
    message: 'Recorded ai_calls row',
  },
}];
